compliant:
// Use named constants instead
#define BUFFER_SIZE 1024
#define HTTP_OK_STATUS 200
#define DAYS_IN_WEEK 7

int buffer[BUFFER_SIZE];
if (status == HTTP_OK_STATUS) {
  processSuccess();
}
for (int i = 0; i < DAYS_IN_WEEK; i++) {
  process(data[i]);
}
